{
  "name": "Endyy's Patisserie",
  "description": "A modern, premium online bakery for pickup and delivery offering fresh cakes, yogurts, and cupcakes."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ProductCategory {
  CAKE = 'Cakes',
  CUPCAKE = 'Cupcakes',
  YOGURT = 'Yogurt Parfaits'
}

export interface Product {
  id: string;
  name: string;
  category: ProductCategory;
  price: number;
  description: string;
  image: string;
  popular: boolean;
  ingredients?: string[];
  calories?: number;
}

export interface CartItem extends Product {
  quantity: number;
}

export enum DeliveryMethod {
  PICKUP = 'Pickup',
  DELIVERY = 'Delivery'
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const getBakerResponse = async (userMessage: string): Promise<string> => {
  if (!apiKey) {
    return "I'm sorry, my baking brain isn't connected right now (Missing API Key). But I recommend the Blueberry Bliss Cake!";
  }

  try {
    const model = ai.models.getGenerativeModel({
      model: "gemini-3-flash-preview",
      systemInstruction: `You are 'Baker Ben', the friendly AI assistant for Endyy's, a premium online cake and dessert shop.

      Brand Tone: Warm, delicious, trustworthy, premium but friendly.
      Brand Colors: Blue, White, Cream.

      Your goal is to help customers choose desserts based on their needs (birthdays, allergies, taste preferences).

      We sell:
      - Cakes (Blueberry Bliss, Royal Chocolate, Ocean Velvet)
      - Cupcakes (Vanilla Bean, Lemon Drizzle, Salted Caramel)
      - Yogurt Parfaits (Morning Berry, Mango Tango)

      Keep responses short (under 50 words), helpful, and always try to sound appetizing. If asked about ingredients, emphasize freshness.`
    });

    const response = await model.generateContent({
      contents: userMessage,
    });

    return response.text || "I'm busy taking a cake out of the oven! Please ask again in a moment.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Oops! I dropped the flour. Can you ask that again?";
  }
};

import React, { useState } from 'react';
import { ShoppingBag, Menu, X, Cake } from 'lucide-react';
import { Link, useLocation } from 'react-router-dom';

interface HeaderProps {
  cartCount: number;
  onOpenCart: () => void;
}

