              className="md:hidden p-2 text-gray-700"
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>

        {/* Mobile Nav Dropdown */}
        {isMobileMenuOpen && (
          <nav className="md:hidden mt-4 pb-4 flex flex-col space-y-4 border-t border-gray-100 pt-4 animate-fadeIn">
            <Link to="/" onClick={() => setIsMobileMenuOpen(false)} className={`text-lg ${isActive('/')}`}>Home</Link>
            <Link to="/shop" onClick={() => setIsMobileMenuOpen(false)} className={`text-lg ${isActive('/shop')}`}>Shop Menu</Link>
            <Link to="/about" onClick={() => setIsMobileMenuOpen(false)} className={`text-lg ${isActive('/about')}`}>Our Story</Link>
            <Link to="/contact" onClick={() => setIsMobileMenuOpen(false)} className={`text-lg ${isActive('/contact')}`}>Contact</Link>
          </nav>
        )}
      </div>
    </header>
  );
};

import React from 'react';
